{% extends "_base/base.html.j2" %}

{# Etiketten-Bogen — überschreibt den Standard-Letterhead, weil das
   bei Labels nur stört. Der Bogen selbst ist die ganze Seite. #}
{% block letterhead %}{% endblock %}
{% block letterhead_small_sender %}{% endblock %}

{% block title %}Item labels {% if data.batchNumber %}#{{ data.batchNumber }}{% endif %}{% endblock %}

{# data['items'], not data.items — attribute lookup wins in Jinja and
   returns the dict's .items METHOD, which breaks the loop below. #}
{% set items = data['items'] | default([]) %}

{% block content %}

  <section class="il-sheet" aria-label="Item labels">
    {% for it in items %}
    <div class="il-label">
      <div class="il-label__sku">{{ it.number }}</div>
      <div class="il-label__name">{{ it.name }}</div>
      <div class="il-label__bottom">
        <div class="il-label__barcode-wrap">
          <div class="barcode-ean" data-code="{{ it.ean | default('') }}"></div>
          <div class="il-label__ean">{{ it.ean | default('') }}</div>
        </div>
        {% if it.price %}
        <div class="il-label__price">{{ it.price }}{% if it.unit %}<span class="il-label__unit">/ {{ it.unit }}</span>{% endif %}</div>
        {% endif %}
      </div>
    </div>
    {% endfor %}
    {# Auffüllen auf 24 (3×8) damit das Grid nicht aufbricht — leere
       Slots als Placeholder, druckbar als "Reserve" oder zum Per-Hand
       beschriften. #}
    {% for _ in range(24 - items|length if items|length < 24 else 0) %}
    <div class="il-label il-label--empty" aria-hidden="true"></div>
    {% endfor %}
  </section>

{% endblock %}

css:
/* A4-Etikettenbogen, 3 × 8 Labels à 70 × 37mm.
   Räume: A4 = 210 × 297mm
       - 3 × 70mm = 210mm (volle Breite, ohne Seitenrand)
       - 8 × 37mm = 296mm  (nahezu volle Höhe — 0.5mm oben/unten Toleranz)
   Avery-3475-kompatibel. */

@page {
  size: A4;
  margin: 0;
}

body {
  margin: 0;
  padding: 0;
}

/* Standard-Letterhead-Bereich wird vom Template per `block letterhead` geleert,
   trotzdem dessen Margin-Reserve sicher killen falls der Base-Style noch was setzt. */
.box-letterhead,
.box-letterhead-small-sender {
  display: none !important;
}

.il-sheet {
  display: grid;
  grid-template-columns: repeat(3, 70mm);
  grid-template-rows: repeat(8, 37mm);
  width: 210mm;
  margin: 0;
}

.il-label {
  width: 70mm;
  height: 37mm;
  padding: 3mm 4mm;
  box-sizing: border-box;
  border: 0.15mm dashed #d1d5db;
  /* Border kommt erst beim Druck als Schnittlinien-Hilfe.
     Echte Roll-Etiketten haben hier nichts. */
  display: flex;
  flex-direction: column;
  justify-content: space-between;
  overflow: hidden;
  font-size: 8.5pt;
  line-height: 1.2;
  color: #111827;
}
.il-label--empty {
  background: repeating-linear-gradient(
    45deg,
    transparent 0 4mm,
    rgba(15,23,42,0.02) 4mm 8mm
  );
}

.il-label__sku {
  font-family: monospace;
  font-size: 8pt;
  font-weight: 700;
  letter-spacing: 0.3pt;
  color: #4b5563;
  text-transform: uppercase;
}

.il-label__name {
  font-size: 10pt;
  font-weight: 700;
  line-height: 1.2;
  max-height: 12mm;
  overflow: hidden;
  display: -webkit-box;
  -webkit-line-clamp: 2;
  -webkit-box-orient: vertical;
}

.il-label__bottom {
  display: flex;
  justify-content: space-between;
  align-items: flex-end;
  gap: 2mm;
}

.il-label__barcode-wrap {
  flex: 1;
  min-width: 0;
}

/* EAN-13-Streifen — schmaler als Code-128 weil EAN feste Modul-Breite hat. */
.barcode-ean {
  height: 8mm;
  background:
    repeating-linear-gradient(
      to right,
      #111827 0 0.4mm,
      transparent 0.4mm 0.7mm,
      #111827 0.7mm 1.0mm,
      transparent 1.0mm 1.6mm,
      #111827 1.6mm 1.9mm,
      transparent 1.9mm 2.5mm,
      #111827 2.5mm 2.8mm,
      transparent 2.8mm 3.5mm
    );
  border-bottom: 0.2mm solid #111827;
}

.il-label__ean {
  font-family: monospace;
  font-size: 7.5pt;
  letter-spacing: 0.4pt;
  margin-top: 0.5mm;
}

.il-label__price {
  font-weight: 700;
  font-size: 11pt;
  white-space: nowrap;
  text-align: right;
  margin-left: auto;
}
.il-label__unit {
  font-weight: 400;
  font-size: 8pt;
  color: #6b7280;
  margin-left: 1mm;
}
